"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"After:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class IntakeCommand extends Command {
    private final IntakeSubsystem intake;

    public IntakeCommand(IntakeSubsystem intake) {
        this.intake = intake;
        addRequirements(intake);
    }

    @Override
