"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"ARESLib:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class FollowPathCommand extends Command {
    private final DriveSubsystem drive;
    private final PathPlannerTrajectory trajectory;
    private final Timer timer = new Timer();

    public FollowPathCommand(DriveSubsystem drive, String pathName) {
        this.drive = drive;
        this.trajectory = PathPlanner.loadPath(pathName, 3.0, 2.0);
        addRequirements(drive);
    }

    @Override
    public void initialize() {
        timer.reset();
        timer.start();
        drive.followTrajectory(trajectory);
    }

    @Override
    public void execute() {
        PathPlannerState targetState = trajectory.sample(timer.get());
        drive.driveToState(targetState);
    }

    @Override
    public boolean isFinished() {
        return timer.hasElapsed(trajectory.getTotalTimeSeconds());
    }
}
