text","text":"Yaw < 0: Turn left."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Yaw Γëê 0: Aimed!"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Hint 3: Distance control"}]},{"type":"paragraph","content":[{"type":"text","text":"Use another PID for distance control:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Too far: Drive forward."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Too close: Drive backward."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Correct distance: Stop and score."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Γ£à Solution"}]},{"type":"paragraph","content":[{"type":"text","text":"≡ƒæü∩╕Å Reveal Solution"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class VisionAimCommand extends Command {
    private final Drivetrain drivetrain;
    private final VisionIO vision;
    private final Shooter shooter;

    private final PIDController turnController;
    private final PIDController distanceController;

    public VisionAimCommand(Drivetrain drivetrain, VisionIO vision, Shooter shooter) {
        this.drivetrain = drivetrain;
        this.vision = vision;
        this.shooter = shooter;

        turnController = new PIDController(3.0, 0, 0.5);
        distanceController = new PIDController(2.0, 0, 0.3);

        addRequirements(drivetrain);
    }

    @Override
    public void execute() {
        // Get target data from vision
        Optional<div data-component="VisionData"></div> target = vision.getTarget();

        if (target.isEmpty()) {
            // No target visible, stop
            drivetrain.drive(0, 0, 0);
            return;
        }

        VisionData data = target.get();

        // Calculate outputs
        double turnOutput = turnController.calculate(data.getYaw(), 0.0);
        double driveOutput = distanceController.calculate(
            data.getDistance(),
            2.0  // Target distance: 2 meters
        );

        // Drive robot
        drivetrain.drive(driveOutput, 0, turnOutput);
    }

    @Override
    public boolean isFinished() {
        // Check if aligned and at correct distance
        Optional<div data-component="VisionData"></div> target = vision.getTarget();
        if (target.isEmpty()) return false;

        VisionData data = target.get();
        boolean aligned = Math.abs(data.getYaw()) < 0.05;  // ~3 degrees
        boolean correctDistance = Math.abs(data.getDistance() - 2.0) < 0.1;  // 10cm

        return aligned && correctDistance;
    }

    @Override
    public void end(boolean interrupted) {
        drivetrain.drive(0, 0, 0);

        // If we finished (not interrupted), score!
        if (!interrupted) {
            shooter.score();
        }
    }
}
