{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Traditional feedforward tuning requires running SysId routines and analyzing logs offline. "},{"type":"text","marks":[{"type":"bold"}],"text":"ARESLib's "},{"type":"text","marks":[{"type":"code"}],"text":"OnlineFeedforwardEstimator"},{"type":"text","text":" automatically tunes your kV and kA gains during normal robot operation!"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"01 What is Live Feedforward Tuning?"}]},{"type":"paragraph","content":[{"type":"text","text":"The "},{"type":"text","marks":[{"type":"code"}],"text":"OnlineFeedforwardEstimator"},{"type":"text","text":" continuously monitors your mechanism's telemetry (voltage, velocity, acceleration) and uses Ordinary Least Squares (OLS) regression to calculate the optimal feedforward constants in real-time."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Why Use This?"}]},{"type":"paragraph","content":[{"type":"text","text":"Method Time Required Data Quality Schedule Required "},{"type":"text","marks":[{"type":"bold"}],"text":"Traditional SysId"},{"type":"text","text":" 15-30 minutes Excellent Dedicated routine "},{"type":"text","marks":[{"type":"bold"}],"text":"Online Estimator"},{"type":"text","text":" Automatic during use Very Good Runs during teleop/auto"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"02 Quick Start"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"2.1 Create the Estimator"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"private OnlineFeedforwardEstimator estimator;

public ElevatorSubsystem(ElevatorIO io) {
    this.io = io;

    // Create estimator with 10-second sliding window
    // kS = 0.1 is your estimated static friction voltage
    estimator = new OnlineFeedforwardEstimator("Elevator", 500, 0.1);
}
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"2.2 Feed Data in Your Loop"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"@Override
public void periodic() {
    // Read hardware inputs
    io.updateInputs(inputs);

    // Feed live data to the estimator
    estimator.addMeasurement(
        inputs.appliedVolts,    // Voltage you applied
        inputs.velocityMetersPerSec,  // Current velocity
        inputs.accelerationMetersPerSecondSq // Can be derived
    );

    // Update your feedforward model with latest estimates
    if (estimator.hasReliableEstimates()) {
        double newKV = estimator.getEstimatedKV();
        double newKA = estimator.getEstimatedKA();

        // Update your feedforward in real-time!
        feedforward = new SimpleMotorFeedforward(0.1, newKV, newKA);
    }
}
