"}]},{"type":"paragraph","content":[{"type":"text","text":"Using OLS regression over a sliding window of recent data points:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Filter"},{"type":"text","text":": Only uses data when velocity > 0.1 m/s (avoids static friction nonlinearity)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Buffer"},{"type":"text","text":": Maintains a circular buffer of recent measurements"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Regress"},{"type":"text","text":": Continuously solves the 2Γö£├╣2 normal equations using Kramer's rule"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Publish"},{"type":"text","text":": Outputs the latest kV and kA estimates"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"3.2 Sliding Window Algorithm"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Internal algorithm (simplified)
public void addMeasurement(double voltage, double velocity, double acceleration) {
    // Skip low-velocity data (static friction region)
    if (Math.abs(velocity) < 0.1) return;

    // Add to sliding window
    buffer[index] = new Measurement(voltage, velocity, acceleration);
    index = (index + 1) % windowSize;

    // Solve OLS regression
    solveOLS(); // Updates currentKV and currentKA
}
"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"04 Practical Usage Examples"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Example 1: Flywheel Tuning"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class ShooterSubsystem extends SubsystemBase {
    private OnlineFeedforwardEstimator ffEstimator;
    private SimpleMotorFeedforward feedforward;

    public ShooterSubsystem() {
        // Initialize with estimated kS
        ffEstimator = new OnlineFeedforwardEstimator("Shooter", 500, 0.05);
        feedforward = new SimpleMotorFeedforward(0.05, 0.1, 0.01);
    }

    @Override
    public void periodic() {
        // Read encoder data
        double velocity = shooterEncoder.getVelocity();
        double voltage = shooterMotor.getMotorVoltage();

        // Estimate acceleration (simple numerical derivative)
        double acceleration = (velocity - lastVelocity) / LOOP_PERIOD_SECS;
        lastVelocity = velocity;

        // Feed to estimator
        ffEstimator.addMeasurement(voltage, velocity, acceleration);

        // Update if we have reliable data
        if (ffEstimator.hasReliableEstimates()) {
            double kV = ffEstimator.getEstimatedKV();
            double kA = ffEstimator.getEstimatedKA();
            feedforward = new SimpleMotorFeedforward(0.05, kV, kA);
        }

        // Use updated feedforward
        double targetVoltage = feedforward.calculate(1500); // 1500 RPM
        shooterMotor.setVoltage(targetVoltage);
    }
}
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Example 2: Elevator Auto-Tuning"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"public class ElevatorSubsystem extends SubsystemBase {
    private OnlineFeedforwardEstimator estimator;

    public void runAutoTune() {
        estimator.reset();

        // Move elevator up and down at varying speeds
        Commands.sequence(
            moveToPosition(0.5, 0.5),  // Move up at 0.5 m/s
            moveToPosition(0.0, 1.0),  // Move down at 1.0 m/s
            moveToPosition(1.0, 0.3),  // Move up at 0.3 m/s
            moveToPosition(0.0, 0.7)   // Move down at 0.7 m/s
        ).schedule();

        // Estimator continuously tunes during movements
        // Check FTC Dashboard for converged values
    }
}
